const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x1a1020);this.words=['GAME','CODE','PLAY','LOOP','BOSS'];this.target=Phaser.Utils.Array.GetRandom(this.words);this.typed='';this.sec=20;this.ui=this.add.text(10,10,`Type: ${this.target}  Time:20`);this.res=this.add.text(W/2,H/2,'',{fontSize:'26px'}).setOrigin(.5);this.input.keyboard.on('keydown',e=>{if(this.over)return;if(e.key==='Backspace')this.typed=this.typed.slice(0,-1);else if(/^[a-zA-Z]$/.test(e.key))this.typed+=(e.key.toUpperCase());if(this.typed===this.target){this.target=Phaser.Utils.Array.GetRandom(this.words);this.typed='';}this.ui.setText(`Type: ${this.target}  Time:${this.sec}  Input:${this.typed}`);});this.time.addEvent({delay:1000,loop:true,callback:()=>{if(this.over)return;this.sec--;this.ui.setText(`Type: ${this.target}  Time:${this.sec}  Input:${this.typed}`);if(this.sec<=0)this.end();}});this.r=this.input.keyboard.addKey('R');}end(){this.over=true;this.res.setText('END\nR');}update(){if(this.r.isDown)this.scene.restart();}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});
